/**
 * One-off generator for `aes-text-base64.json` — an implementation-independent
 * oracle for the legacy `aes-text-base64` decrypt-only method.
 *
 * The legacy on-disk format is the one produced historically by
 * `CryptoJS.AES.encrypt(text, passphrase).toString()`:
 *
 *   base64( "Salted__" || salt[8] || AES-256-CBC(text, key, iv) )
 *
 * where `key` (32 bytes) and `iv` (16 bytes) are derived from the passphrase
 * STRING and the salt via OpenSSL's EVP_BytesToKey (MD5, one iteration), and
 * the cipher is AES-256-CBC with PKCS#7 padding.
 *
 * This script depends ONLY on `node:crypto` (createHash('md5') +
 * createCipheriv('aes-256-cbc', …)) so it is an oracle independent of the
 * WebCrypto implementation under test. Salts are FIXED so the emitted vectors
 * are deterministic and can be committed as known-answer fixtures.
 *
 * Run: `node components/pryv-encryption/test/fixtures/generate-aes-text-base64.js`
 */
'use strict';

const crypto = require('node:crypto');
const fs = require('node:fs');
const path = require('node:path');

/**
 * OpenSSL EVP_BytesToKey with MD5 and a single hashing chain (count = 1).
 * @param {Buffer} passphrase - the passphrase bytes (UTF-8 of the string).
 * @param {Buffer} salt - 8 salt bytes.
 * @param {number} keyLen - key length in bytes (32 for AES-256).
 * @param {number} ivLen - IV length in bytes (16 for CBC).
 * @returns {{ key: Buffer, iv: Buffer }}
 */
function evpBytesToKey (passphrase, salt, keyLen, ivLen) {
  let derived = Buffer.alloc(0);
  let block = Buffer.alloc(0);
  while (derived.length < keyLen + ivLen) {
    const hash = crypto.createHash('md5');
    hash.update(block);
    hash.update(passphrase);
    hash.update(salt);
    block = hash.digest();
    derived = Buffer.concat([derived, block]);
  }
  return { key: derived.subarray(0, keyLen), iv: derived.subarray(keyLen, keyLen + ivLen) };
}

/**
 * Encrypt a material object into a legacy `aes-text-base64` payload.
 * @param {string} passphrase
 * @param {Object} material - the `{ type, content }` object to protect.
 * @param {Buffer} salt - 8 fixed salt bytes.
 * @returns {{ plaintextJson: string, payload: string, saltHex: string }}
 */
function encryptLegacy (passphrase, material, salt) {
  const plaintextJson = JSON.stringify(material);
  const { key, iv } = evpBytesToKey(Buffer.from(passphrase, 'utf8'), salt, 32, 16);
  const cipher = crypto.createCipheriv('aes-256-cbc', key, iv); // PKCS#7 padding by default
  const ciphertext = Buffer.concat([cipher.update(plaintextJson, 'utf8'), cipher.final()]);
  const blob = Buffer.concat([Buffer.from('Salted__', 'ascii'), salt, ciphertext]);
  return { plaintextJson, payload: blob.toString('base64'), saltHex: salt.toString('hex') };
}

const cases = [
  {
    passphrase: 'correct horse battery staple',
    material: { type: 'note/txt', content: 'a legacy secret note' },
    salt: Buffer.from('0102030405060708', 'hex')
  },
  {
    passphrase: 'p@ssw0rd — ünîcode ✓',
    material: { type: 'mass/kg', content: { value: 42, extra: [1, 2, 3] } },
    salt: Buffer.from('a1b2c3d4e5f60718', 'hex')
  }
];

const vectors = cases.map((c) => {
  const { plaintextJson, payload, saltHex } = encryptLegacy(c.passphrase, c.material, c.salt);
  return {
    passphrase: c.passphrase,
    plaintextObject: c.material,
    plaintextJson,
    saltHex,
    payload
  };
});

const out = {
  description: 'Legacy aes-text-base64 known-answer vectors. payload = base64("Salted__" || salt[8] || AES-256-CBC(JSON, key, iv)); key+iv derived from the passphrase STRING via OpenSSL EVP_BytesToKey (MD5, 1 iteration). Generated by generate-aes-text-base64.js using node:crypto as an implementation-independent oracle.',
  vectors
};

const target = path.join(__dirname, 'aes-text-base64.json');
fs.writeFileSync(target, JSON.stringify(out, null, 2) + '\n');
console.log('wrote', target, 'with', vectors.length, 'vectors');
